62	 * @ch Feature Wheel 輪盤 UI 元件
63	 * 單一職責：顯示 12 格、平時 Idle 緩轉、依 server 資料換 icon、轉動落在指定格、播落點演出、把選中功能拋給外部
64	 * 不碰盤面標記/重轉/改符號（呼叫端責任）
65	 */
66	@ccclass('FeatureWheelManager')
67	export class FeatureWheelManager extends Component {
68	    //#region 屬性
69	    /**@ch 根節點（顯示/隱藏）*/
70	    @property({ type: Node, displayName: '根節點' })
71	    private m_rootNode: Node = null;
72	
73	    /**@ch 輪盤旋轉節點（轉動的是這個，頂端指針固定不動）*/
74	    @property({ type: Node, displayName: '輪盤旋轉節點' })
75	    private m_wheelNode: Node = null;
76	
77	    /**@ch 12 格 icon 的 SpriteChange（順序對應格 0~11）*/
78	    @property({ type: [SpriteChange], displayName: '12 格 icon SpriteChange' })
79	    private m_segmentSpriteChanges: SpriteChange[] = [];
80	
81	    /**@ch 12 格乘倍數值 Label（非乘倍格留空字串；順序對應格 0~11）*/
82	    @property({ type: [Label], displayName: '12 格乘倍數值 Label' })
83	    private m_segmentValueLabels: Label[] = [];
84	
85	    /**@ch 12 格落點演出節點（順序對應格 0~11；現僅供 DevAssertConfig 數量檢查，落點演出已改用結果展示牌）*/
86	    @property({ type: [Node], displayName: '12 格落點演出節點' })
87	    private m_segmentNodes: Node[] = [];
88	
89	    /**@ch 結果展示牌根節點（暫代落點演出：顯示落點 feature 符號；退場由 HIDE_RESULT 事件觸發）*/
90	    @property({ type: Node, displayName: '結果展示牌根節點' })
91	    private m_resultNode: Node = null;
92	
93	    /**@ch 結果展示牌符號 SpriteChange（5 張圖索引對齊 TYPE_ICON_CONFIG，與 12 格 icon 同套索引）*/
94	    @property({ type: SpriteChange, displayName: '結果展示牌符號 SpriteChange' })
95	    private m_resultSpriteChange: SpriteChange = null;
96	
97	    /**@ch 轉動方向：勾選=順時針，取消=逆時針（預設順時針）*/
98	    @property({ displayName: '順時針轉動' })
99	    private m_clockwise: boolean = true;
100	
101	    /**@ch Idle 緩轉一圈秒數（越大越慢；≤0 視為不緩轉）；方向跟隨「順時針轉動」*/
102	    @property({ displayName: 'Idle 一圈秒數' })
103	    private m_idleSecondsPerRev: number = 60;
104	    //#endregion 屬性
105	
106	    //#region 常數
107	    /**@ch 轉動時間（秒）；拉長以降低峰值角速度，減輕 12 格重複圖樣的車輪錯覺（視覺反向）*/
108	    private static readonly ROTATE_TIME = 3;//2.5;
109	    //#endregion 常數
110	
111	    //#region 變數
112	    /**@ch 遊戲視窗*/
113	    private m_gameView: GameView = null;
114	    /**@ch 是否初始化*/
115	    private m_isInit = false;
116	    /**@ch 是否轉動中（轉動中/閒置兩互斥態）*/
117	    private m_isSpinning = false;
118	    /**@ch 是否處於 Idle 緩轉態（SHOW_UI/RESUME_IDLE 開、HIDE_UI/PlaySpin 關；轉動中由 m_isSpinning 暫停，轉完不自動恢復）*/
119	    private m_isIdle = false;
120	    /**@ch 是否已註冊事件*/
121	    private m_isEventRegistered = false;
122	    /**@ch 當前 12 格資料*/
123	    private m_segments: SegmentDescriptor[] = [];
124	
125	    /**@ch 事件列表*/
126	    private readonly EVENT_LIST: string[] = [
127	        FEATURE_WHEEL_EVENT.INIT,
128	        FEATURE_WHEEL_EVENT.SET_WHEEL_DATA,
129	        FEATURE_WHEEL_EVENT.PLAY_SPIN,
130	        FEATURE_WHEEL_EVENT.SHOW_UI,
131	        FEATURE_WHEEL_EVENT.HIDE_UI,
132	        FEATURE_WHEEL_EVENT.RESUME_IDLE,
133	        FEATURE_WHEEL_EVENT.HIDE_RESULT,
134	    ];
135	    //#endregion 變數
136	
137	    //#region 生命週期
138	    onLoad() {
139	        this.RegisterEvent();
140	        this.DevAssertConfig();
141	        this.RegisterTestKeyCodes();
142	    }
143	
144	    onDestroy() {
145	        this.UnregisterEvent();
146	        this.UnregisterTestKeyCodes();
147	    }
148	
149	    /**
150	     * @ch 每幀 Idle 緩轉：僅在 Idle 態且非轉動中執行（兩旋轉路徑互斥，不同幀寫 m_wheelNode）
151	     * 方向跟隨 m_clockwise（順時針 = z 遞減，與 ComputeTargetAngle 一致）
152	     */
153	    update(dt: number) {
154	        if (!this.m_isIdle || this.m_isSpinning) {
155	            return;
156	        }
157	        if (this.m_idleSecondsPerRev <= 0) {
158	            return;
159	        }
160	        if (!this.m_wheelNode || !this.m_wheelNode.isValid) {
161	            return;
162	        }
163	        const dir = this.m_clockwise ? -1 : 1;
164	        const deltaAngle = dir * (360 / this.m_idleSecondsPerRev) * dt;
165	        // 正規化防 BC-8 連續累積漂移（與 RotateToIndex 收尾一致），spin 起點讀 currentAngle 仍正確
166	        const next = NormalizeAngle(this.m_wheelNode.eulerAngles.z + deltaAngle);
167	        this.m_wheelNode.setRotationFromEuler(0, 0, next);
168	    }
169	    //#endregion 生命週期
170	
171	    //#region 事件註冊
172	    private RegisterEvent() {
173	        if (this.m_isEventRegistered) {
174	            return;
175	        }
176	        this.m_isEventRegistered = true;
177	        this.EVENT_LIST.forEach(event => eventManager.Register(event, this));
178	    }
179	
180	    private UnregisterEvent() {
181	        if (!this.m_isEventRegistered) {
182	            return;
183	        }
184	        this.EVENT_LIST.forEach(event => eventManager.UnRegister(event, this));
185	        this.m_isEventRegistered = false;
186	    }
187	
188	    /**
189	     * @ch 事件分派
190	     */
191	    OnEvent(event: string, ...args: any[]) {
192	        switch (event) {
193	            case FEATURE_WHEEL_EVENT.INIT:
194	                if (args.length > 0 && typeof args[0] === 'object' && args[0] !== null) {
195	                    this.Init(args[0]);
196	                } else {
197	                    error('FeatureWheel INIT 參數無效');
198	                }
199	                break;
200	
201	            case FEATURE_WHEEL_EVENT.SET_WHEEL_DATA:
202	                if (args.length > 0 && Array.isArray(args[0])) {
203	                    this.SetWheelData(args[0]);
204	                } else {
205	                    error('FeatureWheel SET_WHEEL_DATA 參數無效');
206	                }
207	                break;
208	
209	            case FEATURE_WHEEL_EVENT.PLAY_SPIN:
210	                if (args.length > 0 && typeof args[0] === 'number') {
211	                    this.PlaySpin(args[0], typeof args[1] === 'function' ? args[1] : undefined);
212	                } else {
213	                    error('FeatureWheel PLAY_SPIN 參數無效');
214	                }
215	                break;
216	
217	            case FEATURE_WHEEL_EVENT.SHOW_UI:
218	                this.SetUIShow(true);
219	                break;
220	
221	            case FEATURE_WHEEL_EVENT.HIDE_UI:
222	                this.SetUIShow(false);
223	                break;
224	
225	            case FEATURE_WHEEL_EVENT.RESUME_IDLE:
226	                this.ResumeIdle();
227	                break;
228	
229	            case FEATURE_WHEEL_EVENT.HIDE_RESULT:
230	                this.HideResult();
231	                break;
232	        }
233	    }
234	    //#endregion 事件註冊
235	
236	    //#region 方法
237	    /**
238	     * @ch 初始化（IF-1）
239	     */
240	    private Init(gameView: GameView) {
241	        this.m_gameView = gameView;
242	        this.m_isInit = true;
243	    }

